// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Weather condition to icon/emoji mapping
  const weatherIconMap: Record<string, string> = {
    'Sunny': '☀️',
    'Cloudy': '☁️',
    'Rainy': '🌧️',
    'Snowy': '❄️',
    'Windy': '💨',
    'Stormy': '⛈️',
    'Clear': '🌙',
  };

  const getWeatherIcon = useCallback((condition: string | undefined | null) => {
    if (!condition || typeof condition !== 'string') return '🌡️';
    return weatherIconMap[condition] || '🌡️';
  }, []);

  return { getWeatherIcon };
}

function Component(props: Props) {
  const state = useComponent(props);
  const { getWeatherIcon } = state;
  const tempUnit = props.unit || 'C';
  return (
    <Container maxWidth="xl" padding={24}>
      <Card shadow="md" padding={24}>
        <Stack gap={20}>
          {/* HEADER - City and condition */}
          <Stack gap={8}>
            <Heading level={1}>{props.city}</Heading>
            <Stack direction="horizontal" gap={12} align="center">
              <Text size="2xl">{getWeatherIcon(props.condition)}</Text>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.condition}</Text>
            </Stack>
          </Stack>

          {/* CURRENT CONDITIONS */}
          <Stack gap={16}>
            {/* Temperature - Large and prominent */}
            <Box>
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)" align="center">
                {props.temperature}°{tempUnit}
              </Text>
            </Box>

            {/* Humidity and Wind Speed */}
            <Stack direction="horizontal" gap={24} justify="center">
              <Stack align="center" gap={4}>
                <Icon name="droplets" size={20} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                <Text variant="label" weight="semibold">{props.humidity}%</Text>
              </Stack>
              <Stack align="center" gap={4}>
                <Icon name="wind" size={20} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                <Text variant="label" weight="semibold">{props.windSpeed} m/s</Text>
              </Stack>
            </Stack>
          </Stack>

          {/* DIVIDER */}
          <Divider />

          {/* 5-DAY FORECAST STRIP */}
          <Stack gap={8}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">5-Day Forecast</Text>
            <Stack direction="horizontal" gap={12} wrap>
              {props.forecast && props.forecast.length > 0 ? (
                props.forecast.map((day, idx) => (
                  <Card key={idx} shadow="sm" padding={12} radius="md" border>
                    <Stack align="center" gap={6}>
                      <Text variant="label" weight="semibold" size="sm">{day.day || `Day ${idx + 1}`}</Text>
                       <Text size="2xl">{day.icon || getWeatherIcon('Sunny')}</Text>
                      <Stack gap={2} align="center">
                         <Text variant="caption" weight="semibold">{day.high !== undefined ? `${day.high}°${tempUnit}` : 'N/A'}</Text>
                         <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{day.low !== undefined ? `${day.low}°${tempUnit}` : 'N/A'}</Text>
                      </Stack>
                    </Stack>
                  </Card>
                ))
              ) : (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No forecast data available</Text>
              )}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

function GeneratedComponent(props: Props) {
  return <Component {...props} />;
}

export default GeneratedComponent;

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // Form state for multi-step survey
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [],
    comments: '',
  });

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validation helpers
  const validateEmail = useCallback((email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  const validateStep1 = useCallback((): boolean => {
    let isValid = true;
    setNameError('');
    setEmailError('');

    if (!formData.name.trim()) {
      setNameError('Name is required');
      isValid = false;
    }

    if (!formData.email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(formData.email)) {
      setEmailError('Please enter a valid email address');
      isValid = false;
    }

    return isValid;
  }, [formData.name, formData.email, validateEmail]);

  const isStep2Valid = formData.satisfaction > 0;
  const isStep3Valid = true; // Optional step — no validation required
  const isStep4Valid = true; // Optional step — comments are optional

  // Handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1 && !validateStep1()) return;
    if (currentStep === 4) {
      // Advance to review step (Step 5)
      setCurrentStep(5);
      return;
    }
    if (currentStep === 5) {
      // Submit from final review step
      submit(formData);
      return;
    }
    setCurrentStep(prev => Math.min(prev + 1, 5));
  }, [currentStep, validateStep1, formData, submit]);

  const handleBack = useCallback(() => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  }, []);

  const handleNameChange = useCallback((value: string) => {
    setFormData(prev => ({ ...prev, name: value }));
    setNameError('');
  }, []);

  const handleEmailChange = useCallback((value: string) => {
    setFormData(prev => ({ ...prev, email: value }));
    setEmailError('');
  }, []);

  const handleSatisfactionChange = useCallback((value: string) => {
    setFormData(prev => ({ ...prev, satisfaction: parseInt(value, 10) }));
  }, []);

  const handleFeatureToggle = useCallback((feature: string, checked: boolean) => {
    setFormData(prev => ({
      ...prev,
      features: checked
        ? [...prev.features, feature]
        : prev.features.filter(f => f !== feature),
    }));
  }, []);

  const handleCommentsChange = useCallback((value: string) => {
    if (value.length <= 500) {
      setFormData(prev => ({ ...prev, comments: value }));
    }
  }, []);

  return { submit, currentStep, setCurrentStep, formData, setFormData, nameError, emailError, validateEmail, validateStep1, isStep2Valid, isStep3Valid, isStep4Valid, handleNext, handleBack, handleNameChange, handleEmailChange, handleSatisfactionChange, handleFeatureToggle, handleCommentsChange };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  return (
      <Container maxWidth="md" padding={24}>
        <Stack gap={24}>
          {/* PROGRESS BAR */}
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {state.currentStep > 4 ? 4 : state.currentStep} of 4</Text>
            <Progress value={state.currentStep} max={4} variant="default" size="md" />
          </Stack>

          {/* STEP 1: NAME & EMAIL */}
          {state.currentStep === 1 && (
            <Stack gap={16}>
              <Heading level={2}>Tell us about yourself</Heading>
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={state.formData.name}
                onChange={state.handleNameChange}
                error={state.nameError}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={state.formData.email}
                onChange={state.handleEmailChange}
                error={state.emailError}
                required
              />
            </Stack>
          )}

          {/* STEP 2: SATISFACTION RATING */}
          {state.currentStep === 2 && (
            <Stack gap={16}>
              <Heading level={2}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={state.formData.satisfaction ? String(state.formData.satisfaction) : ''}
                onChange={state.handleSatisfactionChange}
                options={(props.satisfactionLabels || []).map((label, idx) => ({
                  value: String(idx + 1),
                  label: label,
                }))}
                direction="vertical"
              />
            </Stack>
          )}

          {/* STEP 3: FEATURE INTERESTS */}
          {state.currentStep === 3 && (
            <Stack gap={16}>
              <Heading level={2}>What features interest you?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Select at least one</Text>
              <Stack gap={12}>
                 {(props.featureOptions || []).map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={state.formData.features.includes(feature)}
                    onChange={(checked) => state.handleFeatureToggle(feature, checked)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

          {/* STEP 4: COMMENTS */}
          {state.currentStep === 4 && (
            <Stack gap={16}>
              <Heading level={2}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional feedback..."
                value={state.formData.comments}
                onChange={state.handleCommentsChange}
                rows={5}
                maxLength={500}
                showCount
              />
            </Stack>
          )}

          {/* STEP 5: REVIEW (FINAL STEP) */}
          {state.currentStep === 5 && (
            <Stack gap={16}>
              <Heading level={2}>Review Your Answers</Heading>
              <Card padding={16} shadow="sm">
                <Stack gap={12}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                    <Text variant="body">{state.formData.name}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                    <Text variant="body">{state.formData.email}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction Rating</Text>
                    <Text variant="body">{props.satisfactionLabels && state.formData.satisfaction > 0 ? props.satisfactionLabels[state.formData.satisfaction - 1] : 'Not selected'}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Interested Features</Text>
                    <Stack gap={8} direction="horizontal" wrap>
                      {state.formData.features.map((feature) => (
                        <Badge key={feature} variant="primary" size="md">{feature}</Badge>
                      ))}
                    </Stack>
                  </Stack>
                  {state.formData.comments && (
                    <>
                      <Divider />
                      <Stack gap={4}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                        <Text variant="body">{state.formData.comments}</Text>
                      </Stack>
                    </>
                  )}
                </Stack>
              </Card>
            </Stack>
          )}

          {/* NAVIGATION BUTTONS */}
          <Row gap={8} justify="between">
            <Button
              variant="ghost"
              onClick={state.handleBack}
              disabled={state.currentStep === 1}
              style={{ opacity: state.currentStep === 1 ? 0.5 : 1, cursor: state.currentStep === 1 ? 'not-allowed' : 'pointer' }}
            >
              Back
            </Button>
            <Button
              variant="primary"
              onClick={state.handleNext}
              disabled={
                (state.currentStep === 1 && !state.validateStep1()) ||
                (state.currentStep === 2 && !state.isStep2Valid) ||
                (state.currentStep === 4 && !state.isStep4Valid) ||
                (state.currentStep === 5 && false)
              }
              style={{ transition: 'all 200ms ease-in-out' }}
            >
              {state.currentStep === 5 ? 'Submit' : 'Next'}
            </Button>
          </Row>
        </Stack>
      </Container>
    );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state management
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [addingTaskToColumn, setAddingTaskToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');

  // Sync incoming stream updates to local state
  React.useEffect(() => {
    if (taskChanged.latest?.task && taskChanged.latest?.action) {
      const updatedTask = taskChanged.latest.task;
      const action = taskChanged.latest.action;

      if (action === 'delete' && updatedTask.id) {
        setLocalTasks((prev) => (Array.isArray(prev) ? prev.filter((t) => t.id !== updatedTask.id) : []));
      } else if (action === 'create' || action === 'move' || action === 'edit') {
        setLocalTasks((prev) => {
          const prevArray = Array.isArray(prev) ? prev : [];
          const exists = prevArray.find((t) => t.id === updatedTask.id);
          if (exists) {
            return prevArray.map((t) => (t.id === updatedTask.id ? { ...t, ...updatedTask } : t));
          } else {
            return [...prevArray, updatedTask];
          }
        });
      }
    }
  }, [taskChanged.latest]);

  // Handle adding new task
  const handleAddTask = useCallback(
    (columnId: string) => {
      if (!newTaskTitle.trim()) return;

      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: '',
        dueDate: '',
      };

      setLocalTasks((prev) => (Array.isArray(prev) ? [...prev, newTask] : [newTask]));
      taskUpdate({
        action: 'create',
        taskId: newTask.id,
        data: { column: columnId, title: newTaskTitle, priority: newTaskPriority },
      });

      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingTaskToColumn(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  // Handle moving task to another column
  const handleMoveTask = useCallback(
    (taskId: string, targetColumn: string) => {
      setLocalTasks((prev) =>
        Array.isArray(prev) ? prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t)) : []
      );
      taskUpdate({
        action: 'move',
        taskId: taskId || '',
        data: { column: targetColumn },
      });
    },
    [taskUpdate]
  );

  // Handle editing task title
  const handleEditTask = useCallback(
    (taskId: string) => {
      if (!editingTaskTitle.trim()) {
        setEditingTaskId(null);
        return;
      }

      setLocalTasks((prev) =>
        Array.isArray(prev) ? prev.map((t) => (t.id === taskId ? { ...t, title: editingTaskTitle } : t)) : []
      );
      const currentTask = Array.isArray(localTasks) ? localTasks.find((t) => t.id === taskId) : undefined;
      taskUpdate({
        action: 'edit',
        taskId: taskId || '',
        data: { column: currentTask?.column || 'todo', title: editingTaskTitle },
      });

      setEditingTaskId(null);
      setEditingTaskTitle('');
    },
    [editingTaskTitle, taskUpdate, localTasks]
  );

  // Calculate statistics
  const totalTasks = Array.isArray(localTasks) ? localTasks.length : 0;
  const completedTasks = Array.isArray(localTasks) ? localTasks.filter((t) => t.column === 'done').length : 0;

  // Get tasks by column
  const getTasksByColumn = useCallback(
    (columnId: string) => {
      if (!columnId || !Array.isArray(localTasks)) return [];
      return localTasks.filter((t) => t.column === columnId) || [];
    },
    [localTasks]
  );

  return {
    taskUpdate,
    taskChanged,
    localTasks,
    addingTaskToColumn,
    setAddingTaskToColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    editingTaskId,
    setEditingTaskId,
    editingTaskTitle,
    setEditingTaskTitle,
    handleAddTask,
    handleMoveTask,
    handleEditTask,
    totalTasks,
    completedTasks,
    getTasksByColumn,
  };
}


export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        {/* HEADER WITH SUMMARY */}
        <Stack gap={8}>
          <Heading level={1}>Task Board</Heading>
          <Row gap={16} align="center" justify="start">
            <Text variant="body">
              Total: <Text is="span" weight="semibold">{state.totalTasks}</Text>
            </Text>
            <Text variant="body">
              Completed: <Text is="span" weight="semibold" color="var(--ggui-color-success-600, #16a34a)">{state.completedTasks}</Text>
            </Text>
          </Row>
        </Stack>

        {/* KANBAN BOARD */}
        <Row gap={16} align="start" justify="start" wrap>
          {(props.columns || []).map((column) => {
            const columnId = column?.id || 'todo';
            const columnName = column?.name || 'Unnamed';
            const columnTasks = state.getTasksByColumn(columnId) || [];
            return (
              <div key={columnId} style={{ flex: '0 1 320px', minWidth: '300px' }}>
                <Card padding={16} shadow="md">
                  <Stack gap={12}>
                    {/* COLUMN HEADER */}
                    <Row gap={8} justify="between" align="center">
                      <Heading level={3}>{columnName}</Heading>
                      <Badge variant="secondary" size="sm">
                        {columnTasks.length}
                      </Badge>
                    </Row>

                    <Divider margin={8} />

                    {/* TASK LIST */}
                    <Stack gap={8}>
                      {columnTasks.map((task) => {
                        const taskId = task?.id || '';
                        return (
                          <Card key={taskId || `empty-${Math.random()}`} padding={12} shadow="sm" border radius="md">
                            <Stack gap={8}>
                              {/* TASK TITLE (EDITABLE) */}
                              {state.editingTaskId === taskId ? (
                                <Stack gap={6} direction="horizontal">
                                  <Input
                                    label="Edit task"
                                    value={state.editingTaskTitle}
                                    onChange={state.setEditingTaskTitle}
                                    size="sm"
                                  />
                                  <Button
                                    size="sm"
                                    variant="primary"
                                    onClick={() => state.handleEditTask(taskId)}
                                  >
                                    Save
                                  </Button>
                                </Stack>
                               ) : (
                                 <Box
                                   as={Clickable}
                                   onClick={() => {
                                     state.setEditingTaskId(taskId);
                                     state.setEditingTaskTitle(task?.title || '');
                                   }}
                                   padding={8}
                                   borderRadius={4}
                                 >
                                   <Stack gap={4}>
                                     <Text variant="body" weight="medium">
                                       {task?.title || 'Untitled'}
                                     </Text>
                                     <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                       Click to edit
                                     </Text>
                                   </Stack>
                                 </Box>
                               )}
                              {/* PRIORITY BADGE */}
                              {task?.priority && (
                                <Badge
                                  variant={
                                    task.priority === 'high'
                                      ? 'error'
                                      : task.priority === 'medium'
                                      ? 'warning'
                                      : 'success'
                                  }
                                  size="sm"
                                >
                                  {task.priority}
                                </Badge>
                              )}

                              {/* ASSIGNEE & DUE DATE */}
                              <Row gap={8} align="center" justify="start">
                                {task?.assignee && (
                                  <Avatar name={task.assignee} size="sm" />
                                )}
                                {task?.dueDate && (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                    {task.dueDate}
                                  </Text>
                                )}
