// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [props.elements, searchQuery]);

  // Get unique categories and count elements per category
  const categoryColors: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'alkaline-earth-metal': 'var(--ggui-color-info-100, #cffafe)',
    'lanthanide': 'var(--ggui-color-success-100, #dcfce7)',
    'actinide': 'var(--ggui-color-warning-100, #fef3c7)',
    'transition-metal': 'var(--ggui-color-primary-50, #f0f9ff)',
    'post-transition-metal': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    'nonmetal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'halogen': 'var(--ggui-color-error-100, #fee2e2)',
    'noble-gas': 'var(--ggui-color-success-100, #dcfce7)',
    'metalloid': 'var(--ggui-color-warning-100, #fef3c7)',
  };

  const getCategoryColor = useCallback(
    (category?: string): string => {
      return categoryColors[category?.toLowerCase().replace(/\s+/g, '-') || ''] || 'var(--ggui-color-surface, #fafafa)';
    },
    []
  );

  const getCategoryTextColor = useCallback(
    (category?: string): string => {
      const cat = category?.toLowerCase().replace(/\s+/g, '-') || '';
      if (['halogen', 'nonmetal'].includes(cat)) return 'var(--ggui-color-error-700, #b91c1c)';
      if (['noble-gas', 'alkaline-earth-metal'].includes(cat)) return 'var(--ggui-color-success-700, #15803d)';
      if (['lanthanide', 'actinide'].includes(cat)) return 'var(--ggui-color-warning-700, #b45309)';
      return 'var(--ggui-color-onSurface, #18181b)';
    },
    []
  );

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    getCategoryColor,
    getCategoryTextColor,
    categoryColors,
  };
}

