}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State for quantity selector
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const maxQuantity = props.product.stock ?? 0;
  const isOutOfStock = maxQuantity === 0;
  const stockStatus = maxQuantity > 10 ? 'In Stock' : maxQuantity > 0 ? 'Low Stock' : 'Out of Stock';
  const stockColor = maxQuantity > 10 ? 'success' : maxQuantity > 0 ? 'warning' : 'error';

  // Handlers
  const handleQuantityChange = useCallback((newQty: number) => {
    const clamped = Math.max(1, Math.min(newQty, maxQuantity));
    setQuantity(clamped);
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  return {
    quantity,
    setQuantity: handleQuantityChange,
    activeTab,
    setActiveTab,
    maxQuantity,
    isOutOfStock,
    stockStatus,
    stockColor,
    handleAddToCart,
  };
}

