                        data={(props.product.specifications as Array<{ key?: string; value?: string }>).map((spec, idx) => ({
                          key: spec?.key || `spec-${idx}`,
                          value: spec?.value || '-',
                        }))}
                      />
                    ) : (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications available.</Text>
                    )}
                  </Stack>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: (
                  <Stack gap={16}>
                    {Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
                      props.product.reviews.map((review: any, idx: number) => (
                        <Card key={idx} padding={16} shadow="none" border={true}>
                          <Stack gap={8}>
                            <Row gap={8} align="center">
                              <Text variant="label" weight="semibold">{review?.author || 'Anonymous'}</Text>
                              <Badge variant="primary" size="sm">{review?.rating || 0} ★</Badge>
                            </Row>
                            <Text variant="body">{review?.text || review?.comment || '-'}</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{review?.date || new Date().toLocaleDateString()}</Text>
                          </Stack>
                        </Card>
                      ))
                    ) : (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet.</Text>
                    )}
                  </Stack>
                ),
              },
            ]}
            activeKey={state.activeTab}
            onChange={state.setActiveTab}
          />
        </Card>

        {/* BOTTOM SECTION — Quantity + Add to Cart */}
        <Card shadow="md" padding={24}>
          <Stack gap={16}>
            {/* Quantity Selector */}
            <Stack gap={8}>
              <Text variant="label">Quantity</Text>
              <Row gap={8} align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => state.setQuantity(state.quantity - 1)}
                  disabled={state.quantity <= 1}
                >
                  −
                </Button>
                <Text variant="body" style={{ minWidth: '40px', textAlign: 'center' }}>{state.quantity}</Text>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => state.setQuantity(state.quantity + 1)}
                  disabled={state.quantity >= state.maxQuantity}
                >
                  +
                </Button>
              </Row>
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              fullWidth
              onClick={state.handleAddToCart}
              disabled={state.isOutOfStock}
            >
              {state.isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

