            <div ref={state.messagesEndRef} />
          </Stack>
        )}
      </Card>

      {/* INPUT AREA */}
      <Card shadow="md" padding={12}>
        <Stack direction="horizontal" gap={8} align="end">
          <TextArea
            label="Message"
            placeholder="Type your message... (Enter to send, Shift+Enter for newline)"
            value={state.inputText}
            onChange={state.setInputText}
            onKeyDown={state.handleKeyPress}
            rows={2}
          />
          <Button
            variant="primary"
            size="md"
            onClick={state.handleSendMessage}
            disabled={!state.inputText.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Card>
    </Stack>
  );
}
  );
}

