import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [lastUpdateTime, setLastUpdateTime] = useState<Date | null>(null);
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const highlightTimeoutRef = useRef<Record<string, NodeJS.Timeout>>({});

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Merge price updates into display stocks
  React.useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setDisplayStocks((prev) =>
        prev.map((stock) =>
          stock.symbol === update.symbol
            ? {
                ...stock,
                price: update.price ?? stock.price,
                change: update.change ?? stock.change,
                changePercent: update.changePercent ?? stock.changePercent,
              }
            : stock
        )
      );
      setLastUpdateTime(new Date());

      // Flash highlight animation
      if (update.symbol) {
        if (highlightTimeoutRef.current[update.symbol]) {
          clearTimeout(highlightTimeoutRef.current[update.symbol]);
        }
        setHighlightedSymbols((prev) => new Set(prev).add(update.symbol!));
        highlightTimeoutRef.current[update.symbol] = setTimeout(() => {
          setHighlightedSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol!);
            return next;
          });
          delete highlightTimeoutRef.current[update.symbol!];
        }, 600);
      }
    }
  }, [priceUpdate.latest]);

  return {
    displayStocks,
    lastUpdateTime,
    highlightedSymbols,
    priceUpdate,
    marketStatus,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const { displayStocks, lastUpdateTime, highlightedSymbols, marketStatus } = state;

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>Market Watch</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Last Updated: {lastUpdateTime ? lastUpdateTime.toLocaleTimeString() : 'Loading...'}
          </Text>
        </Stack>

        {/* MARKET STATUS */}
        {marketStatus.latest && (
          <Alert
            variant={marketStatus.latest.status === 'open' ? 'success' : 'info'}
            title={`Market ${marketStatus.latest.status?.toUpperCase() || 'UNKNOWN'}`}
          >
            {marketStatus.latest.timestamp && `as of ${new Date(marketStatus.latest.timestamp).toLocaleTimeString()}`}
          </Alert>
        )}

        {/* STOCK CARDS GRID */}
         {/* STOCK CARDS GRID - Responsive: 3 cols desktop, 1 col mobile */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {displayStocks.length === 0 ? (
            <Box
              padding={24}
              style={{
                gridColumn: '1 / -1',
                textAlign: 'center',
              }}
            >
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks available
              </Text>
            </Box>
          ) : (
            displayStocks.map((stock) => {
              const isPositive = (stock.changePercent ?? 0) >= 0;
              const isHighlighted = highlightedSymbols.has(stock.symbol ?? '');

              return (
                <Card
                  key={stock.symbol}
                  padding={16}
                  shadow="md"
                  radius="lg"
                  style={{
                    borderLeft: `4px solid ${isPositive ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-error-500, #ef4444)'}`,
                    transition: isHighlighted ? 'background-color 0.3s ease' : 'none',
                    backgroundColor: isHighlighted
                      ? isPositive
                        ? 'var(--ggui-color-success-50, #f0fdf4)'
                        : 'var(--ggui-color-error-50, #fef2f2)'
                      : 'var(--ggui-color-surface, #fafafa)',
                  }}
                >
                  <Stack gap={12}>
                    {/* Ticker and Company Name */}
                    <div>
                      <Text
                        variant="overline"
                        color={isPositive ? 'var(--ggui-color-success-700, #15803d)' : 'var(--ggui-color-error-700, #b91c1c)'}
                      >
                        {stock.symbol?.toUpperCase() || 'N/A'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name || 'Unknown'}
                      </Text>
                    </div>

                    {/* Price and Change */}
                    <Stack gap={4}>
                      <Text
                        size="2xl"
                        weight="bold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        ${(stock.price ?? 0).toFixed(2)}
                      </Text>
                      <div
                        style={{
                          display: 'flex',
                          alignItems: 'center',
                          gap: 'var(--ggui-spacing-1, 4px)',
                        }}
                      >
                        <Text
                          variant="bodySmall"
                          color={isPositive ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)'}
                          weight="semibold"
                        >
                          {isPositive ? '▲' : '▼'} {Math.abs(stock.change ?? 0).toFixed(2)} ({Math.abs(stock.changePercent ?? 0).toFixed(2)}%)
                        </Text>
                      </div>
                    </Stack>
                  </Stack>
                </Card>
              );
            })
          )}
        </div>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // Step and form state
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications !== false);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // Validation
  const nameError = name.trim() === '' ? 'Name is required' : '';
  const emailError = email.trim() === '' ? 'Email is required' : !isValidEmail(email) ? 'Invalid email format' : '';
  const avatarError = !avatar ? 'Avatar selection required' : '';

  const isStep1Valid = nameError === '' && emailError === '' && avatarError === '';

  // Handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep < 3) setCurrentStep(currentStep + 1);
  }, [currentStep, isStep1Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid) return;
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [complete, name, email, avatar, role, emailNotifications, theme, isStep1Valid]);

  return {
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    avatar,
    setAvatar,
    role,
    setRole,
    emailNotifications,
    setEmailNotifications,
    theme,
    setTheme,
    nameError,
    emailError,
    avatarError,
    isStep1Valid,
    handleNext,
    handleBack,
    handleComplete,
  };
}

function isValidEmail(email: string): boolean {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

export default function Component(props: Props) {
