                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role:</Text>
                        <Text variant="body">{state.role || '—'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications:</Text>
                        <Badge variant={state.emailNotifications ? 'success' : 'default'} size="sm">
                          {state.emailNotifications ? 'On' : 'Off'}
                        </Badge>
                      </Stack>
                      <Stack direction="horizontal" justify="between" align="center">
