                          {state.theme === 'dark' ? 'Dark' : 'Light'}
                        </Badge>
                      </Stack>
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* NAVIGATION BUTTONS */}
        <Stack direction="horizontal" gap={12} justify="between" align="center">
          {state.currentStep > 1 && (
            <Button
              variant="ghost"
              onClick={state.handleBack}
